#!/usr/bin/env node
// patch-m2-service-worker-offline.mjs — Sprint M2: Service Worker (App-Shell
// offline, Kern-Hash-Cache, Update-Hinweis) + Naming-Korrektur raumzuzweit/roomfortwo.
// BASIS (Reihenfolge verbindlich): origin/main @ 195f30d (patch-s81)
//   + patch-m1-pwa-manifest-icons.mjs  ← MUSS zuerst angewendet sein.
// Ganzdatei-Ersetzung mit SHA-256-Ankerprüfung (Abweichung → melden, nicht
// überschreiben), idempotent, --dry-run. Kern-Hash danach: c685b0970a4cdf9f.

import { readFile, writeFile, mkdir } from "node:fs/promises";
import { createHash } from "node:crypto";
import path from "node:path";

const DRY = process.argv.includes("--dry-run");
const sha = b => createHash("sha256").update(b).digest("hex");

const DATEIEN = [
  {
    "pfad": "scripts/build-pages.js",
    "art": "ersetzen",
    "altSha": "cc8aed243908b706b357ff8f15cfeb5e3c344c18e264596cb1860bc6d14e8354",
    "neuSha": "dee6939ac77d909129b22e6252675a19dfe1652f0cb173c49e1d6a4ac5d2970f",
    "daten": ""
  },
  {
    "pfad": "platforms/cloudflare/pages/client.js",
    "art": "ersetzen",
    "altSha": "ffbc68b0aa557e48e0b6bc1c0a298c43c76e79b832af89636f7e5392331d4517",
    "neuSha": "7a77ee2adfae25c97296065c06f75338d654aec9d26a07062e3bbe9a02877067",
    "daten": ""
  },
  {
    "pfad": "core/i18n/de.js",
    "art": "ersetzen",
    "altSha": "fa352344f1622079932e0f572aaad10707ad34e8de961bf0fb118dcdce0bab7c",
    "neuSha": "42434c7db1d080f9383e48be4501a06beb23de9ee8a11fb681629ebc344530a0",
    "daten": ""
  },
  {
    "pfad": "core/i18n/en.js",
    "art": "ersetzen",
    "altSha": "026de59a09cbcb993e136e248606da10a8667912c48519c7f63c7f6f215f7852",
    "neuSha": "b3b51d3c5aaafe1c4931718104e2a1efd2a5f4ae60931eb7a1536ab4b2cc0f12",
    "daten": ""
  },
  {
    "pfad": "platforms/cloudflare/pages/sw-routing.js",
    "art": "neu",
    "neuSha": "c17b1c407f2c56efd054dec0dc3c40e85346dc3c28e319b19234f4c22768b757",
    "daten": ""
  },
  {
    "pfad": "platforms/cloudflare/pages/sw.js",
    "art": "neu",
    "neuSha": "e0f4aa697c38904d50cb07a4927c8def4268a25a056472e05bea3f1a4be1ad51",
    "daten": ""
  },
  {
    "pfad": "tests/unit/m2-service-worker.spec.js",
    "art": "neu",
    "neuSha": "233266972d9d53a58df4350053101a402a53c1b07bc83807e4158349f66d9b97",
    "daten": ""
  },
  {
    "pfad": "docs/SPRINT-M2-PROTOKOLL.md",
    "art": "neu",
    "neuSha": "2d9eafd19726fdaa3ecf6383a5b7959443a3142fc84a4bdd928567fcdbd3a753",
    "daten": ""
  }
];

let fehler = 0, angewendet = 0, uebersprungen = 0;
for (const d of DATEIEN) {
  const ziel = path.resolve(d.pfad);
  const neuBuf = Buffer.from(d.daten, "base64");
  if (sha(neuBuf) !== d.neuSha) { console.error(`✗ ${d.pfad}: eingebettete Daten beschädigt`); fehler++; continue; }
  let vorhanden = null;
  try { vorhanden = await readFile(ziel); } catch {}
  if (vorhanden && sha(vorhanden) === d.neuSha) { console.log(`= ${d.pfad}: bereits angewendet`); uebersprungen++; continue; }
  if (d.art === "ersetzen") {
    if (!vorhanden) { console.error(`✗ ${d.pfad}: fehlt — falsches Verzeichnis oder M1-Patch nicht angewendet?`); fehler++; continue; }
    if (sha(vorhanden) !== d.altSha) {
      console.error(`✗ ${d.pfad}: Altstand weicht ab (erwartet ${d.altSha.slice(0,12)}…, gefunden ${sha(vorhanden).slice(0,12)}…) — M1 zuerst anwenden? Nicht überschrieben.`);
      fehler++; continue;
    }
  } else if (vorhanden) {
    console.error(`✗ ${d.pfad}: existiert bereits mit fremdem Inhalt — nicht überschrieben`); fehler++; continue;
  }
  if (DRY) { console.log(`→ ${d.pfad}: würde ${d.art === "ersetzen" ? "ersetzt" : "angelegt"}`); angewendet++; continue; }
  await mkdir(path.dirname(ziel), { recursive: true });
  await writeFile(ziel, neuBuf);
  console.log(`✓ ${d.pfad}: ${d.art === "ersetzen" ? "ersetzt" : "angelegt"}`);
  angewendet++;
}
console.log(`\n${DRY ? "Trockenlauf" : "Patch"}: ${angewendet} ${DRY ? "geplant" : "angewendet"}, ${uebersprungen} übersprungen, ${fehler} Fehler.`);
if (fehler) process.exit(1);
if (!DRY && angewendet) console.log("Weiter mit: npx vitest run && npm run build");
